interface SentimentRecord {
  t:   number;  // tier 1-5
  l:   string;  // label
  c:   string;  // color
  bg:  string;  // background
  d:   number;  // depth
  s:   number;  // specificity
  w:   number;  // warmth
  p:   number;  // personalization
  tot: number;  // total raw score
}

interface RecipientSA {
  avg:   number;
  dist:  Record<string, number>;
  hf:    number;  // heartfelt count (tier 4-5)
  perf:  number;  // perfunctory count (tier 1)
  total: number;
}

interface NominatorSA {
  name:  string;
  dept:  string;
  avg:   number;
  hf:    number;
  total: number;
}

interface SentimentData {
  awards:     Record<string, SentimentRecord>;
  recipients: Record<string, RecipientSA>;
  monthly:    Record<string, number>;
  nominators: Record<string, NominatorSA>;
}

